  7→  --color-falcon-success: #10b981;
  8→  --color-falcon-error: #ef4444;
  9→
 10→  /* Dark theme defaults */
 11→  --color-falcon-bg: #0f172a;
 12→  --color-falcon-surface: #1e293b;
 13→  --color-falcon-text: #f8fafc;
 14→  --color-falcon-muted: #94a3b8;
 15→}
 16→
 17→/* ─── Dark mode ─────────────────────────────────────────────────────── */
 18→.dark {
 19→  --color-falcon-bg: #0f172a;
 20→  --color-falcon-surface: #1e293b;
 21→  --color-falcon-text: #f8fafc;
