 33→
 34→  --mesh-gradient:
 35→    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.08) 0%, transparent 50%),
 36→    radial-gradient(ellipse at 80% 20%, rgba(6, 182, 212, 0.06) 0%, transparent 50%),
 37→    radial-gradient(ellipse at 50% 100%, rgba(16, 185, 129, 0.04) 0%, transparent 50%);
 38→}
 39→
 40→/* ─── Light mode ────────────────────────────────────────────────────── */
 41→.light {
 42→  --color-falcon-bg: #fafbfd;
 43→  --color-falcon-surface: #f1f5f9;
 44→  --color-falcon-text: #0f172a;
 45→  --color-falcon-muted: #64748b;
 46→
 47→  /* Glass tokens — light */
 48→  --glass-bg: rgba(255, 255, 255, 0.60);
 49→  --glass-bg-heavy: rgba(255, 255, 255, 0.75);
 50→  --glass-border: rgba(0, 0, 0, 0.06);
 51→  --glass-border-hover: rgba(0, 0, 0, 0.10);
 52→  --glass-shadow: 0 8px 40px -12px rgba(0, 0, 0, 0.08);
 53→  --glass-shadow-glow: 0 0 30px -5px rgba(99, 102, 241, 0.12);
 54→  --glass-shadow-success: 0 0 30px -5px rgba(16, 185, 129, 0.12);
 55→  --glass-shadow-error: 0 0 30px -5px rgba(239, 68, 68, 0.12);
 56→
 57→  --mesh-gradient:
 58→    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.06) 0%, transparent 50%),
 59→    radial-gradient(ellipse at 80% 20%, rgba(6, 182, 212, 0.05) 0%, transparent 50%),
 60→    radial-gradient(ellipse at 50% 100%, rgba(16, 185, 129, 0.04) 0%, transparent 50%);
 61→}
 62→
 63→/* ─── Base ──────────────────────────────────────────────────────────── */
 64→html {
 65→  scroll-behavior: smooth;
 66→}
 67→
 68→@media (prefers-reduced-motion: reduce) {
 69→  html {
 70→    scroll-behavior: auto;
 71→  }
 72→}
 73→
 74→body {
 75→  background: var(--mesh-gradient), var(--color-falcon-bg);
 76→  min-height: 100vh;
 77→}
 78→
 79→/* Subtle grain texture overlay */
 80→body::before {
 81→  content: "";
 82→  position: fixed;
 83→  inset: 0;
 84→  z-index: 0;
 85→  pointer-events: none;
 86→  opacity: 0.025;
 87→  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
 88→  background-repeat: repeat;
 89→  background-size: 256px 256px;
 90→}
 91→
 92→body > main {
 93→  position: relative;
 94→  z-index: 1;
 95→}
 96→
 97→/* Selection highlight */
 98→::selection {
 99→  background-color: rgba(99, 102, 241, 0.20);
100→}
101→
102→/* ─── Glass card utility classes ────────────────────────────────────── */
103→.glass-card {
104→  background: var(--glass-bg);
105→  backdrop-filter: blur(20px);
106→  -webkit-backdrop-filter: blur(20px);
107→  border: 1px solid var(--glass-border);
108→  border-radius: 1rem;
109→  box-shadow: var(--glass-shadow);
110→  transition: all 0.3s cubic-bezier(0.32, 0.72, 0, 1);
111→}
112→
113→.glass-card:hover {
114→  background: var(--glass-bg-heavy);
115→  border-color: var(--glass-border-hover);
116→  transform: translateY(-1px);
117→  box-shadow: var(--glass-shadow), var(--glass-shadow-glow);
118→}
119→
120→.glass-card-static {
121→  background: var(--glass-bg);
122→  backdrop-filter: blur(20px);
123→  -webkit-backdrop-filter: blur(20px);
124→  border: 1px solid var(--glass-border);
125→  border-radius: 1rem;
126→  box-shadow: var(--glass-shadow);
127→}
128→
129→.glass-nav {
130→  background: var(--glass-bg-heavy);
131→  backdrop-filter: blur(40px);
132→  -webkit-backdrop-filter: blur(40px);
133→  border-bottom: 1px solid var(--glass-border);
134→}
135→
136→/* ─── Scroll-triggered entrance animations ──────────────────────────── */
137→.fade-in-section {
138→  opacity: 0;
139→  transform: translateY(20px);
140→  transition: opacity 0.7s cubic-bezier(0.32, 0.72, 0, 1),
141→              transform 0.7s cubic-bezier(0.32, 0.72, 0, 1);
142→}
143→
144→.fade-in-section.visible {
145→  opacity: 1;
146→  transform: translateY(0);
147→}
148→
149→/* Staggered children */
150→.fade-in-section.visible > .stagger-child {
151→  opacity: 1;
152→  transform: translateY(0);
153→}
154→
155→.stagger-child {
156→  opacity: 0;
157→  transform: translateY(12px);
158→  transition: opacity 0.5s cubic-bezier(0.32, 0.72, 0, 1),
159→              transform 0.5s cubic-bezier(0.32, 0.72, 0, 1);
160→}
161→
162→.stagger-child:nth-child(1) { transition-delay: 0ms; }
163→.stagger-child:nth-child(2) { transition-delay: 60ms; }
164→.stagger-child:nth-child(3) { transition-delay: 120ms; }
165→.stagger-child:nth-child(4) { transition-delay: 180ms; }
166→.stagger-child:nth-child(5) { transition-delay: 240ms; }
167→.stagger-child:nth-child(6) { transition-delay: 300ms; }
168→
169→/* Respect reduced motion */
170→@media (prefers-reduced-motion: reduce) {
171→  .fade-in-section,
172→  .stagger-child {
173→    opacity: 1;
174→    transform: none;
175→    transition: none;
176→  }
177→}
178→
179→/* ─── Skeleton shimmer for loading states ───────────────────────────── */
180→@keyframes shimmer {
181→  0% { background-position: -200% 0; }
182→  100% { background-position: 200% 0; }
183→}
184→
185→.skeleton-shimmer {
186→  background: linear-gradient(
187→    90deg,
188→    var(--glass-bg) 25%,
189→    var(--glass-bg-heavy) 50%,
190→    var(--glass-bg) 75%
191→  );
192→  background-size: 200% 100%;
193→  animation: shimmer 2s ease-in-out infinite;
194→  border-radius: 0.75rem;
195→}
