 1→import { Atom } from "@effect-atom/atom"
 2→import { Option } from "effect"
 3→import { ContractAddress, TxHash } from "../services/types"
 4→import { DEFAULT_NETWORK } from "../config/networks"
 5→import type { NetworkId } from "../config/networks"
 6→
 7→export type { NetworkId }
 8→
 9→export type DeployStep =
10→  | { step: "idle" }
11→  | { step: "generating-keypair" }
12→  | { step: "packing" }
13→  | { step: "computing-address" }
14→  | { step: "awaiting-funds"; address: ContractAddress }
15→  | { step: "deploying"; address: ContractAddress }
16→  | { step: "deployed"; address: ContractAddress; txHash: TxHash }
17→  | { step: "sending-tx"; address: ContractAddress }
18→  | { step: "tx-confirmed"; address: ContractAddress; txHash: TxHash; transferTxHash: TxHash }
19→  | { step: "error"; message: string }
20→
21→export const deployStepAtom = Atom.make<DeployStep>({ step: "idle" }).pipe(
22→  Atom.keepAlive,
23→)
24→
25→export const deployedAddressAtom = Atom.make<Option.Option<ContractAddress>>(Option.none()).pipe(
26→  Atom.keepAlive,
27→)
28→
29→export const deployTxHashAtom = Atom.make<Option.Option<TxHash>>(Option.none()).pipe(
30→  Atom.keepAlive,
31→)
32→
33→const NETWORK_STORAGE_KEY = "falcon-demo-network"
34→
35→function readStoredNetwork(): NetworkId {
36→  try {
37→    if (typeof window === "undefined" || typeof localStorage === "undefined") {
38→      return DEFAULT_NETWORK
39→    }
40→    const stored = localStorage.getItem(NETWORK_STORAGE_KEY)
41→    if (stored === "mainnet" || stored === "sepolia" || stored === "devnet") {
42→      return stored
43→    }
44→    return DEFAULT_NETWORK
45→  } catch {
46→    return DEFAULT_NETWORK
47→  }
48→}
49→
50→export const networkAtom = Atom.make<NetworkId>(readStoredNetwork()).pipe(
51→  Atom.keepAlive,
52→)
53→
54→export { NETWORK_STORAGE_KEY }
