 1→import { Effect, Schema } from "effect"
 2→import type { FalconKeypair, FalconKeyFile, PackedPublicKey } from "./types"
 3→
 4→const Q = 12289
 5→
 6→export class KeyFileParseError extends Schema.TaggedError<KeyFileParseError>()(
 7→  "KeyFileParseError",
 8→  { message: Schema.String },
 9→) {}
10→
11→function bytesToHex(bytes: Uint8Array): string {
12→  return Array.from(bytes)
13→    .map((b) => b.toString(16).padStart(2, "0"))
14→    .join("")
15→}
16→
17→function hexToBytes(hex: string): Uint8Array {
18→  const clean = hex.startsWith("0x") ? hex.slice(2) : hex
19→  const bytes = new Uint8Array(clean.length / 2)
20→  for (let i = 0; i < bytes.length; i++) {
21→    bytes[i] = parseInt(clean.slice(i * 2, i * 2 + 2), 16)
22→  }
23→  return bytes
24→}
25→
26→export function exportKeyFile(
27→  keypair: FalconKeypair,
28→  packedPublicKey: PackedPublicKey,
29→): string {
30→  const file: FalconKeyFile = {
31→    version: 1,
32→    algorithm: "falcon-512",
33→    secretKey: "0x" + bytesToHex(keypair.secretKey),
34→    verifyingKey: "0x" + bytesToHex(keypair.verifyingKey),
35→    publicKeyNtt: Array.from(keypair.publicKeyNtt),
36→    packedPublicKey: Array.from(packedPublicKey.slots),
37→  }
38→  return JSON.stringify(file, null, 2)
39→}
40→
41→export const parseKeyFile = Effect.fn("KeyFile.parse")(
42→  function* (json: string) {
43→    const raw = yield* Effect.try({
44→      try: () => JSON.parse(json) as Record<string, unknown>,
45→      catch: () => new KeyFileParseError({ message: "Invalid JSON" }),
46→    })
47→
48→    if (raw.version !== 1) {
49→      return yield* Effect.fail(
50→        new KeyFileParseError({ message: `Unsupported version: ${raw.version}` }),
51→      )
52→    }
53→    if (raw.algorithm !== "falcon-512") {
54→      return yield* Effect.fail(
55→        new KeyFileParseError({ message: `Unsupported algorithm: ${raw.algorithm}` }),
56→      )
57→    }
58→    if (typeof raw.secretKey !== "string" || typeof raw.verifyingKey !== "string") {
59→      return yield* Effect.fail(
60→        new KeyFileParseError({ message: "Missing secretKey or verifyingKey" }),
61→      )
62→    }
63→    if (!Array.isArray(raw.publicKeyNtt) || !Array.isArray(raw.packedPublicKey)) {
64→      return yield* Effect.fail(
65→        new KeyFileParseError({ message: "Missing publicKeyNtt or packedPublicKey" }),
66→      )
67→    }
68→
69→    for (const coeff of raw.publicKeyNtt as number[]) {
70→      if (typeof coeff !== "number" || coeff < 0 || coeff >= Q) {
71→        return yield* Effect.fail(
72→          new KeyFileParseError({
73→            message: `publicKeyNtt coefficient out of range: ${coeff}`,
74→          }),
75→        )
76→      }
77→    }
78→
79→    const keypair: FalconKeypair = {
80→      secretKey: hexToBytes(raw.secretKey as string),
81→      verifyingKey: hexToBytes(raw.verifyingKey as string),
82→      publicKeyNtt: new Int32Array(raw.publicKeyNtt as number[]),
83→    }
84→
85→    const packedPublicKey: PackedPublicKey = {
86→      slots: raw.packedPublicKey as string[],
87→    }
88→
89→    return { keypair, packedPublicKey }
90→  },
91→)
92→

