@import "tailwindcss";

@theme {
  /* Brand colors */
  --color-falcon-primary: #6366f1;
  --color-falcon-accent: #06b6d4;
  --color-falcon-success: #10b981;
  --color-falcon-error: #ef4444;

  /* Dark theme defaults */
  --color-falcon-bg: #0f172a;
  --color-falcon-surface: #1e293b;
  --color-falcon-text: #f8fafc;
  --color-falcon-muted: #94a3b8;
}

/* ─── Dark mode ─────────────────────────────────────────────────────── */
.dark {
  --color-falcon-bg: #0f172a;
  --color-falcon-surface: #1e293b;
  --color-falcon-text: #f8fafc;
  --color-falcon-muted: #94a3b8;

  /* Glass tokens — dark */
  --glass-bg: rgba(255, 255, 255, 0.04);
  --glass-bg-heavy: rgba(255, 255, 255, 0.06);
  --glass-border: rgba(255, 255, 255, 0.06);
  --glass-border-hover: rgba(255, 255, 255, 0.1);
  --glass-shadow: 0 8px 40px -12px rgba(0, 0, 0, 0.5);
  --glass-shadow-glow: 0 0 30px -5px rgba(99, 102, 241, 0.15);
  --glass-shadow-success: 0 0 30px -5px rgba(16, 185, 129, 0.15);
  --glass-shadow-error: 0 0 30px -5px rgba(239, 68, 68, 0.15);

  --mesh-gradient:
    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.08) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(6, 182, 212, 0.06) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 100%, rgba(16, 185, 129, 0.04) 0%, transparent 50%);
}

/* ─── Light mode ────────────────────────────────────────────────────── */
.light {
  --color-falcon-bg: #fafbfd;
  --color-falcon-surface: #f1f5f9;
  --color-falcon-text: #0f172a;
  --color-falcon-muted: #64748b;

  /* Glass tokens — light */
  --glass-bg: rgba(255, 255, 255, 0.60);
  --glass-bg-heavy: rgba(255, 255, 255, 0.75);
  --glass-border: rgba(0, 0, 0, 0.06);
  --glass-border-hover: rgba(0, 0, 0, 0.10);
  --glass-shadow: 0 8px 40px -12px rgba(0, 0, 0, 0.08);
  --glass-shadow-glow: 0 0 30px -5px rgba(99, 102, 241, 0.12);
  --glass-shadow-success: 0 0 30px -5px rgba(16, 185, 129, 0.12);
  --glass-shadow-error: 0 0 30px -5px rgba(239, 68, 68, 0.12);

  --mesh-gradient:
    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.06) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(6, 182, 212, 0.05) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 100%, rgba(16, 185, 129, 0.04) 0%, transparent 50%);
}

/* ─── Base ──────────────────────────────────────────────────────────── */
html {
  scroll-behavior: smooth;
}

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }
}

body {
  background: var(--mesh-gradient), var(--color-falcon-bg);
  min-height: 100vh;
}

/* Subtle grain texture overlay */
body::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: 0.025;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  background-repeat: repeat;
  background-size: 256px 256px;
}

body > main {
  position: relative;
  z-index: 1;
}

/* Selection highlight */
::selection {
  background-color: rgba(99, 102, 241, 0.20);
}

/* ─── Glass card utility classes ────────────────────────────────────── */
.glass-card {
  background: var(--glass-bg);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid var(--glass-border);
  border-radius: 1rem;
  box-shadow: var(--glass-shadow);
  transition: all 0.3s cubic-bezier(0.32, 0.72, 0, 1);
}

.glass-card:hover {
  background: var(--glass-bg-heavy);
  border-color: var(--glass-border-hover);
  transform: translateY(-1px);
  box-shadow: var(--glass-shadow), var(--glass-shadow-glow);
}

.glass-card-static {
  background: var(--glass-bg);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid var(--glass-border);
  border-radius: 1rem;
  box-shadow: var(--glass-shadow);
}

.glass-nav {
  background: var(--glass-bg-heavy);
  backdrop-filter: blur(40px);
  -webkit-backdrop-filter: blur(40px);
  border-bottom: 1px solid var(--glass-border);
}

/* ─── Scroll-triggered entrance animations ──────────────────────────── */
.fade-in-section {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.7s cubic-bezier(0.32, 0.72, 0, 1),
              transform 0.7s cubic-bezier(0.32, 0.72, 0, 1);
}

.fade-in-section.visible {
  opacity: 1;
  transform: translateY(0);
}

/* Staggered children */
.fade-in-section.visible > .stagger-child {
  opacity: 1;
  transform: translateY(0);
}

.stagger-child {
  opacity: 0;
  transform: translateY(12px);
  transition: opacity 0.5s cubic-bezier(0.32, 0.72, 0, 1),
              transform 0.5s cubic-bezier(0.32, 0.72, 0, 1);
}

.stagger-child:nth-child(1) { transition-delay: 0ms; }
.stagger-child:nth-child(2) { transition-delay: 60ms; }
.stagger-child:nth-child(3) { transition-delay: 120ms; }
.stagger-child:nth-child(4) { transition-delay: 180ms; }
.stagger-child:nth-child(5) { transition-delay: 240ms; }
.stagger-child:nth-child(6) { transition-delay: 300ms; }

/* Respect reduced motion */
@media (prefers-reduced-motion: reduce) {
  .fade-in-section,
  .stagger-child {
    opacity: 1;
    transform: none;
    transition: none;
  }
}

/* ─── Skeleton shimmer for loading states ───────────────────────────── */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.skeleton-shimmer {
  background: linear-gradient(
    90deg,
    var(--glass-bg) 25%,
    var(--glass-bg-heavy) 50%,
    var(--glass-bg) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 2s ease-in-out infinite;
  border-radius: 0.75rem;
}

import type { Metadata } from "next"
import type { ReactNode } from "react"
import { Inter } from "next/font/google"
import Providers from "./providers"
import "./globals.css"

const inter = Inter({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-inter",
})

export const metadata: Metadata = {
  title: "Falcon-512 | Post-Quantum Signatures on Starknet",
  description:
    "Demo of Falcon-512 post-quantum signature verification for Starknet account abstraction. 63K steps, 62 calldata felts.",
}

export default function RootLayout({ children }: { readonly children: ReactNode }) {
  return (
    <html lang="en" className={`dark ${inter.variable}`}>
      <body className="bg-falcon-bg text-falcon-text antialiased font-[family-name:var(--font-inter)]">
        <Providers>{children}</Providers>
      </body>
    </html>
  )
}

import { Config, Effect, Layer } from "effect"
import { RpcProvider, Account, hash } from "starknet"
import type { SignerInterface } from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
  DevnetFetchError,
  TransactionSubmitError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey, DevnetAccount } from "./types"

/** STRK token contract address (same on mainnet and Sepolia) */
export const STRK_TOKEN_ADDRESS =
  "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"

export function parsePrefundedAccounts(raw: unknown[]): DevnetAccount[] {
  return raw
    .filter((item): item is Record<string, string> =>
      typeof item === "object" && item !== null &&
      "address" in item && "private_key" in item
    )
    .map((item) => ({
      address: item.address,
      private_key: item.private_key,
      initial_balance: item.initial_balance ?? "0",
    }))
}

function makeService(rpcUrl: string, classHash: string) {
  const provider = new RpcProvider({ nodeUrl: rpcUrl })

  // Falcon-512 verification needs ~50M L2 gas steps — too heavy for
  // auto-estimation. Hardcode amounts, fetch live prices from the network.
  const falconResourceBounds = Effect.tryPromise({
    try: async () => {
      const block = await provider.getBlock("latest")
      const mul = 2n
      const l1 = BigInt(block.l1_gas_price.price_in_fri) * mul
      const l2 = BigInt(block.l2_gas_price.price_in_fri) * mul
      const l1d = BigInt(block.l1_data_gas_price.price_in_fri) * mul
      return {
        l2_gas: { max_amount: 0x2FAF080n, max_price_per_unit: l2 },
        l1_gas: { max_amount: 0x0n, max_price_per_unit: l1 },
        l1_data_gas: { max_amount: 0x3000n, max_price_per_unit: l1d },
      }
    },
    catch: (error) =>
      new StarknetRpcError({ message: `Gas price fetch failed: ${error}`, code: -1 }),
  })

  const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
    function* (packedPk: PackedPublicKey) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      // Deterministic salt — same keypair always produces the same address,
      // so a pre-funded address stays valid across page reloads.
      const salt = "0x1"
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )
      return {
        address: ContractAddress.make(address),
        salt,
      }
    },
  )

  const isDeployed = Effect.fn("Starknet.isDeployed")(
    function* (address: string) {
      return yield* Effect.tryPromise({
        try: async () => {
          const ch = await provider.getClassHashAt(address)
          return !!ch
        },
        catch: () => new StarknetRpcError({ message: "getClassHashAt failed", code: -1 }),
      }).pipe(Effect.orElseSucceed(() => false))
    },
  )

  const getBalance = Effect.fn("Starknet.getBalance")(
    function* (address: string) {
      return yield* Effect.tryPromise({
        try: async () => {
          const result = await provider.callContract({
            contractAddress: STRK_TOKEN_ADDRESS,
            entrypoint: "balanceOf",
            calldata: [address],
          })
          return BigInt(result[0])
        },
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const deployAccount = Effect.fn("Starknet.deployAccount")(
    function* (
      packedPk: PackedPublicKey,
      signer: SignerInterface,
      salt: string,
    ) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )

      const account = new Account({ provider, address, signer })

      const resourceBounds = yield* falconResourceBounds

      const result = yield* Effect.tryPromise({
        try: () =>
          account.deployAccount(
            {
              classHash,
              constructorCalldata,
              addressSalt: salt,
              contractAddress: address,
            },
            { resourceBounds },
          ),
        catch: (error) =>
          new AccountDeployError({ message: String(error) }),
      })

      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(result.transaction_hash),
        catch: (error) =>
          new AccountDeployError({
            message: `Tx failed: ${error}`,
            txHash: result.transaction_hash,
          }),
      })

      return {
        txHash: TxHash.make(result.transaction_hash),
        address: ContractAddress.make(result.contract_address),
      }
    },
  )

  const waitForTx = Effect.fn("Starknet.waitForTx")(
    function* (txHash: string) {
      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(txHash),
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const fetchPrefundedAccounts = Effect.fn("Starknet.fetchPrefundedAccounts")(
    function* () {
      return yield* Effect.tryPromise({
        try: async () => {
          const baseUrl = rpcUrl.replace(/\/rpc.*$/, "").replace(/\/$/, "")
          const response = await fetch(baseUrl, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              jsonrpc: "2.0",
              id: 1,
              method: "devnet_getPredeployedAccounts",
              params: [],
            }),
          })
          if (!response.ok) {
            throw new Error(`HTTP ${response.status}`)
          }
          const json = await response.json()
          if (json.error) {
            throw new Error(json.error.message ?? JSON.stringify(json.error))
          }
          return parsePrefundedAccounts(json.result as unknown[])
        },
        catch: (error) =>
          new DevnetFetchError({ message: `Failed to fetch prefunded accounts: ${error}` }),
      })
    },
  )

  const sendTransaction = Effect.fn("Starknet.sendTransaction")(
    function* (
      accountAddress: string,
      signer: SignerInterface,
      recipient: string,
      amount: bigint,
    ) {
      const account = new Account({ provider, address: accountAddress, signer })

      const resourceBounds = yield* falconResourceBounds

      return yield* Effect.tryPromise({
        try: async () => {
          const result = await account.execute(
            [
              {
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "transfer",
                calldata: [recipient, amount.toString(), "0"],
              },
            ],
            { resourceBounds },
          )
          await provider.waitForTransaction(result.transaction_hash)
          return { txHash: TxHash.make(result.transaction_hash) }
        },
        catch: (error) =>
          new TransactionSubmitError({ message: String(error) }),
      })
    },
  )

  return {
    computeDeployAddress,
    isDeployed,
    getBalance,
    deployAccount,
    waitForTx,
    fetchPrefundedAccounts,
    sendTransaction,
    provider,
  }
}

// @ts-ignore — StarknetService.make() intentionally overrides the inherited Effect.Service.make() with a Layer factory
export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      return makeService(rpcUrl, "0x0")
    }),
  },
) {
  /**
   * Custom layer factory for runtime network switching.
   * Use this instead of Default when you need a specific rpcUrl and classHash
   * (e.g., switching between Sepolia and Mainnet at runtime).
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  static make(rpcUrl: string, classHash: string): Layer.Layer<StarknetService> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return Layer.succeed(StarknetService, makeService(rpcUrl, classHash) as any)
  }
}

import { Cause, Exit, type ManagedRuntime, Option } from "effect"
import {
  type Call,
  type InvocationsSignerDetails,
  type DeployAccountSignerDetails,
  type DeclareSignerDetails,
  type Signature,
  type TypedData,
  SignerInterface,
  hash,
  transaction,
  CallData,
  EDAMode,
  type EDataAvailabilityMode,
  typedData as typedDataUtils,
} from "starknet"
import { FalconService } from "./FalconService"
import { TransactionSignError } from "./errors"

function intDAM(dam: EDataAvailabilityMode): EDAMode {
  if (dam === "L1") return EDAMode.L1
  if (dam === "L2") return EDAMode.L2
  throw new Error(`Unknown EDataAvailabilityMode: ${dam}`)
}

export class FalconSigner extends SignerInterface {
  constructor(
    private readonly sk: Uint8Array,
    private readonly pkNtt: Int32Array,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    private readonly runtime: ManagedRuntime.ManagedRuntime<FalconService, any>,
  ) {
    super()
  }

  async getPubKey(): Promise<string> {
    // Falcon public keys are not a single felt — return a placeholder.
    // The actual PK is the 29 packed felt252 slots stored in the contract.
    return "0x0"
  }

  async signMessage(
    typedDataObj: TypedData,
    accountAddress: string,
  ): Promise<Signature> {
    const msgHash = typedDataUtils.getMessageHash(typedDataObj, accountAddress)
    return this._signHash(msgHash)
  }

  async signTransaction(
    transactions: Call[],
    transactionsDetail: InvocationsSignerDetails,
  ): Promise<Signature> {
    const compiledCalldata = transaction.getExecuteCalldata(
      transactions,
      transactionsDetail.cairoVersion,
    )
    const txHash = hash.calculateInvokeTransactionHash({
      ...transactionsDetail,
      senderAddress: transactionsDetail.walletAddress,
      compiledCalldata,
      version: transactionsDetail.version,
      nonceDataAvailabilityMode: intDAM(transactionsDetail.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(transactionsDetail.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  async signDeployAccountTransaction(
    details: DeployAccountSignerDetails,
  ): Promise<Signature> {
    const compiledConstructorCalldata = CallData.compile(
      details.constructorCalldata,
    )
    const txHash = hash.calculateDeployAccountTransactionHash({
      ...details,
      salt: details.addressSalt,
      compiledConstructorCalldata,
      version: details.version,
      nonceDataAvailabilityMode: intDAM(details.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(details.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  async signDeclareTransaction(
    details: DeclareSignerDetails,
  ): Promise<Signature> {
    const txHash = hash.calculateDeclareTransactionHash({
      ...details,
      version: details.version,
      nonceDataAvailabilityMode: intDAM(details.nonceDataAvailabilityMode),
      feeDataAvailabilityMode: intDAM(details.feeDataAvailabilityMode),
    })
    return this._signHash(txHash)
  }

  private async _signHash(txHash: string): Promise<string[]> {
    const exit = await this.runtime.runPromiseExit(
      FalconService.signForStarknet(this.sk, txHash, this.pkNtt),
    )

    if (Exit.isSuccess(exit)) {
      console.log("[FalconSigner] txHash:", txHash)
      console.log("[FalconSigner] sig length:", exit.value.length)
      console.log("[FalconSigner] sig[28] (last s1):", exit.value[28])
      console.log("[FalconSigner] sig[29] (salt_len):", exit.value[29])
      console.log("[FalconSigner] sig[30] (salt[0]):", exit.value[30])
      console.log("[FalconSigner] sig[31] (salt[1]):", exit.value[31])
      console.log("[FalconSigner] sig[32] (first hint):", exit.value[32])
      console.log("[FalconSigner] sig[60] (last hint):", exit.value[60])
      return exit.value
    }

    const errOpt = Cause.failureOption(exit.cause)
    const msg = Option.match(errOpt, {
      onNone: () => "Falcon signing failed",
      onSome: (e) => e.message,
    })
    throw new TransactionSignError({ message: msg })
  }
}

import { Schema } from "effect"

export class WasmLoadError extends Schema.TaggedError<WasmLoadError>()(
  "WasmLoadError",
  { message: Schema.String },
) {}

export class KeygenError extends Schema.TaggedError<KeygenError>()(
