                      <p className="text-xs text-falcon-text/30">
                        Balance:{" "}
                        <span className={balance > 0n ? "text-falcon-success/80" : "text-falcon-text/30"}>
                          {(Number(balance) / 1e18).toFixed(4)} STRK
                        </span>
                        {balance > 0n && (
                          <span className="ml-2 text-falcon-success/60">Ready to deploy</span>
                        )}
