          {deployStep.step === "awaiting-funds" && (
            <button
              onClick={handleDeploy}
              className="rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20"
            >
              Deploy Account
            </button>
          )}
        </div>

        {deployStep.step === "deployed" && (
          <>
            <div
              role="status"
              aria-live="polite"
              className="glass-card-static mt-8 rounded-2xl p-6"
              style={{ boxShadow: "var(--glass-shadow-success)", borderColor: "rgba(16, 185, 129, 0.15)" }}
            >
              <h3 className="text-sm font-semibold text-falcon-success/80">Account Deployed</h3>
              <p className="mt-3 break-all font-mono text-xs text-falcon-text/50">
                Address: {deployStep.address}
              </p>
              <p className="mt-1 break-all font-mono text-xs text-falcon-text/50">Tx: {deployStep.txHash}</p>
              {networkConfig.explorerBaseUrl && (
                <a
                  href={`${networkConfig.explorerBaseUrl}/tx/${deployStep.txHash}`}
                  target="_blank"
                  rel="noreferrer noopener"
                  className="mt-4 inline-block text-xs text-falcon-accent/60 transition-colors duration-200 hover:text-falcon-accent"
                >
                  View on Voyager &rarr;
                </a>
              )}
            </div>
            <SendTransaction
              deployedAddress={deployStep.address}
              deployRuntime={deployRuntimeRef.current}
              falconRuntime={falconRuntime}
            />
          </>
        )}

        {deployStep.step === "error" && (
          <div
            role="alert"
            aria-live="polite"
            className="glass-card-static mt-8 rounded-2xl p-6"
            style={{ boxShadow: "var(--glass-shadow-error)", borderColor: "rgba(239, 68, 68, 0.15)" }}
          >
            <p className="text-sm text-falcon-error/80">{deployStep.message}</p>
            <button
              onClick={handleReset}
              className="mt-4 rounded-lg px-4 py-1.5 text-xs text-falcon-text/40 transition-all duration-200 hover:text-falcon-text/70"
              style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
            >
              Try Again
            </button>
          </div>
        )}
      </div>
    </section>
  )
}

"use client"

import React, { useCallback, useState } from "react"
import { Cause, Exit, Option } from "effect"
import { useAtomValue } from "@effect-atom/atom-react"
import { keypairAtom } from "@/atoms/falcon"
import { networkAtom } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import { StarknetService } from "@/services/StarknetService"
import { FalconSigner } from "@/services/FalconSigner"
import type { ContractAddress } from "@/services/types"
import type { ManagedRuntime } from "effect"
import type { FalconService } from "@/services/FalconService"

interface SendTransactionProps {
  readonly deployedAddress: ContractAddress
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly deployRuntime: ManagedRuntime.ManagedRuntime<FalconService | StarknetService, any>
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  readonly falconRuntime: ManagedRuntime.ManagedRuntime<FalconService, any>
}

export function SendTransaction({
  deployedAddress,
  deployRuntime,
  falconRuntime,
}: SendTransactionProps): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const [recipient, setRecipient] = useState(deployedAddress as string)
  const [amount, setAmount] = useState("0.001")
  const [sending, setSending] = useState(false)
  const [result, setResult] = useState<{ txHash: string } | null>(null)
  const [error, setError] = useState<string | null>(null)

  const handleSend = useCallback(async () => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    if (!kp) return

    setSending(true)
    setError(null)
    setResult(null)

    const signer = new FalconSigner(kp.secretKey, kp.publicKeyNtt, falconRuntime)
    const amountWei = BigInt(Math.floor(parseFloat(amount) * 1e18))

    const exit = await deployRuntime.runPromiseExit(
      StarknetService.sendTransaction(
        deployedAddress as string,
        signer,
        recipient,
        amountWei,
      ),
    )

    setSending(false)

    if (Exit.isSuccess(exit)) {
      setResult({ txHash: exit.value.txHash })
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      setError(
        Option.match(errOpt, {
          onNone: () => "Transaction failed",
          onSome: (e) => e.message,
        }),
      )
    }
  }, [keypair, deployedAddress, recipient, amount, deployRuntime, falconRuntime])

  return (
    <div className="glass-card-static mt-8 rounded-2xl p-6">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Test Your Falcon Account</h3>
      <p className="mt-1.5 text-xs text-falcon-text/30">
        Send STRK using your post-quantum account.
      </p>

      <div className="mt-5 space-y-4">
        <div>
          <label htmlFor="tx-recipient" className="block text-xs font-medium text-falcon-text/30">
            Recipient
          </label>
          <input
            id="tx-recipient"
            type="text"
            value={recipient}
            onChange={(e) => setRecipient(e.target.value)}
            className="mt-2 w-full rounded-xl px-4 py-3 font-mono text-sm text-falcon-text/80 transition-all duration-200 focus:outline-none focus:ring-1 focus:ring-falcon-primary/30"
            style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
          />
        </div>

        <div>
          <label htmlFor="tx-amount" className="block text-xs font-medium text-falcon-text/30">
            Amount (STRK)
          </label>
          <input
            id="tx-amount"
            type="text"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            className="mt-2 w-full rounded-xl px-4 py-3 font-mono text-sm text-falcon-text/80 transition-all duration-200 focus:outline-none focus:ring-1 focus:ring-falcon-primary/30"
            style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
          />
        </div>

        <button
          onClick={handleSend}
          disabled={sending || !Option.isSome(keypair)}
          className="rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
        >
          {sending ? "Sending..." : "Send STRK"}
        </button>
      </div>

      {result !== null && (
        <div
          className="glass-card-static mt-5 rounded-2xl p-5"
          style={{ boxShadow: "var(--glass-shadow-success)", borderColor: "rgba(16, 185, 129, 0.15)" }}
        >
          <p className="text-sm font-medium text-falcon-success/80">Transaction Confirmed</p>
          <p className="mt-2 break-all font-mono text-xs text-falcon-text/50">
            Tx: {result.txHash}
          </p>
          {networkConfig.explorerBaseUrl && (
            <a
              href={`${networkConfig.explorerBaseUrl}/tx/${result.txHash}`}
              target="_blank"
              rel="noreferrer noopener"
              className="mt-3 inline-block text-xs text-falcon-accent/60 transition-colors duration-200 hover:text-falcon-accent"
            >
              View on Voyager &rarr;
            </a>
          )}
        </div>
      )}

      {error !== null && (
        <div
          className="glass-card-static mt-5 rounded-2xl p-5"
          style={{ boxShadow: "var(--glass-shadow-error)", borderColor: "rgba(239, 68, 68, 0.15)" }}
        >
          <p className="text-sm text-falcon-error/80">{error}</p>
        </div>
      )}
    </div>
  )
}

import { Effect, Option, Schema } from "effect"
import type { SignerInterface } from "starknet"
import { FalconService } from "@/services/FalconService"
import { StarknetService } from "@/services/StarknetService"
import { InsufficientFundsError } from "@/services/errors"
import { TxHash } from "@/services/types"
import type {
  ContractAddress,
  FalconKeypair,
  PackedPublicKey,
} from "@/services/types"

const FALCON_PUBLIC_KEY_LENGTH = 512
const FALCON_MODULUS = 12289

export class InvalidPrivateKeyError extends Schema.TaggedError<InvalidPrivateKeyError>()(
  "InvalidPrivateKeyError",
  { message: Schema.String },
) {}

export class InvalidPublicKeyNttError extends Schema.TaggedError<InvalidPublicKeyNttError>()(
  "InvalidPublicKeyNttError",
  { message: Schema.String },
) {}

export interface PreparedAccountDeploy {
  readonly privateKey: string
  readonly keypair: FalconKeypair
  readonly packedPublicKey: PackedPublicKey
  readonly address: ContractAddress
  readonly salt: string
}

export interface DeployAccountInput {
  readonly address: ContractAddress
  readonly packedPublicKey: PackedPublicKey
  readonly signer: SignerInterface
  readonly salt: string
  readonly requiredBalance: bigint
}

export const validateHexPrivateKey = Effect.fn(
  "AccountDeployPipeline.validateHexPrivateKey",
)((privateKey: string) =>
  Effect.try({
    try: () => {
      const trimmed = privateKey.trim()
      const normalized = trimmed.toLowerCase()

      if (!normalized.startsWith("0x")) {
        throw new Error("Private key must be 0x-prefixed")
      }

      const hexBody = normalized.slice(2)
      if (hexBody.length === 0 || hexBody.length > 64) {
        throw new Error("Private key must be between 1 and 32 bytes hex")
      }

      if (!/^[0-9a-f]+$/u.test(hexBody)) {
        throw new Error("Private key contains non-hex characters")
      }

      // Pad to 32 bytes for consistency (Starknet private keys may be shorter)
      return `0x${hexBody.padStart(64, "0")}`
    },
    catch: (error) =>
      new InvalidPrivateKeyError({
        message: String(error),
      }),
  }),
)

export const toUint16PublicKeyNtt = Effect.fn(
  "AccountDeployPipeline.toUint16PublicKeyNtt",
)((publicKeyNtt: Int32Array) =>
  Effect.try({
    try: () => {
      if (publicKeyNtt.length !== FALCON_PUBLIC_KEY_LENGTH) {
        throw new Error(
          `publicKeyNtt must have ${FALCON_PUBLIC_KEY_LENGTH} coefficients`,
        )
      }

      const packed = new Uint16Array(FALCON_PUBLIC_KEY_LENGTH)
      for (let i = 0; i < publicKeyNtt.length; i += 1) {
        const coeff = publicKeyNtt[i]
        if (coeff < 0 || coeff >= FALCON_MODULUS) {
          throw new Error(`publicKeyNtt coefficient out of range at index ${i}`)
        }
        packed[i] = coeff
      }

      return packed
    },
    catch: (error) =>
      new InvalidPublicKeyNttError({
        message: String(error),
      }),
  }),
)

interface PrepareAccountDeployInput {
  readonly privateKey: string
  readonly existingKeypair: Option.Option<FalconKeypair>
}

export const prepareAccountDeployEffect = Effect.fn(
  "AccountDeployPipeline.prepareAccountDeployEffect",
)(function* ({ privateKey, existingKeypair }: PrepareAccountDeployInput) {
  // Validate deployer private key only if provided (devnet auto-fills it;
  // on public networks the Falcon account self-deploys so it's not needed).
  const normalizedPrivateKey = privateKey.trim().length > 0
    ? yield* validateHexPrivateKey(privateKey)
    : ""

  const keypair = yield* Option.match(existingKeypair, {
    onNone: () => FalconService.generateKeypair(),
    onSome: (currentKeypair) => Effect.succeed(currentKeypair),
  })

  const publicKeyNtt = yield* toUint16PublicKeyNtt(keypair.publicKeyNtt)
  const packedPublicKey = yield* FalconService.packPublicKey(publicKeyNtt)
  const { address, salt } = yield* StarknetService.computeDeployAddress(packedPublicKey)

  return {
    privateKey: normalizedPrivateKey,
    keypair,
    packedPublicKey,
    address,
    salt,
  } satisfies PreparedAccountDeploy
})

export const deployAccountEffect = Effect.fn(
  "AccountDeployPipeline.deployAccountEffect",
)(function* ({
  address,
  packedPublicKey,
  signer,
  salt,
  requiredBalance,
}: DeployAccountInput) {
  // Skip deploy if account is already live (idempotent re-runs).
  const alreadyDeployed = yield* StarknetService.isDeployed(address)
  if (alreadyDeployed) {
    return { txHash: TxHash.make("already-deployed"), address }
  }

  const balance = yield* StarknetService.getBalance(address)

  if (balance < requiredBalance) {
    return yield* Effect.fail(
      new InsufficientFundsError({
        message: "Insufficient STRK balance. Fund the account and try again.",
        address,
        required: requiredBalance.toString(),
      }),
    )
  }

  const deployment = yield* StarknetService.deployAccount(
    packedPublicKey,
    signer,
    salt,
  )

  return deployment
})

"use client"

import React, { useCallback, useState } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  packedKeyAtom,
  verificationStepAtom,
  wasmStatusAtom,
} from "@/atoms/falcon"
import { exportKeyFile, parseKeyFile } from "@/services/keyfile"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex } from "./verification-utils"

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

export function KeyManagementPanel(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const packedKey = useAtomValue(packedKeyAtom)
  const step = useAtomValue(verificationStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setWasmStatus = useAtomSet(wasmStatusAtom)

  const [showNtt, setShowNtt] = useState(false)
  const [showPacked, setShowPacked] = useState(false)

  const isBusy = step.step === "generating-keypair"

  const packPublicKey = useCallback(
    async (pkNtt: Int32Array) => {
      const pkNtt16 = new Uint16Array(pkNtt.length)
      for (let i = 0; i < pkNtt.length; i++) pkNtt16[i] = pkNtt[i]
      const exit = await appRuntime.runPromiseExit(
        FalconService.packPublicKey(pkNtt16),
      )
      if (Exit.isSuccess(exit)) {
        setPackedKey(Option.some(exit.value))
      }
    },
    [setPackedKey],
  )

  const handleGenerate = useCallback(async () => {
    setStep({ step: "generating-keypair" })
    setPackedKey(Option.none())
    const seed = crypto.getRandomValues(new Uint8Array(32))

    const exit = await appRuntime.runPromiseExit(
      FalconService.generateKeypair(seed),
    )

    if (Exit.isSuccess(exit)) {
      setKeypair(Option.some(exit.value))
      setWasmStatus("ready")
      setStep({ step: "idle" })
      await packPublicKey(exit.value.publicKeyNtt)
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Keypair generation failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
    }
  }, [setKeypair, setPackedKey, setStep, setWasmStatus, packPublicKey])

  const handleImport = useCallback(() => {
    const input = document.createElement("input")
    input.type = "file"
    input.accept = ".json"
    input.onchange = async () => {
      const file = input.files?.[0]
      if (!file) return
      const text = await file.text()
      const exit = await appRuntime.runPromiseExit(parseKeyFile(text))

      if (Exit.isSuccess(exit)) {
        setKeypair(Option.some(exit.value.keypair))
        setPackedKey(Option.some(exit.value.packedPublicKey))
        setWasmStatus("ready")
        setStep({ step: "idle" })
      } else {
        const errOpt = Cause.failureOption(exit.cause)
        const msg = Option.match(errOpt, {
          onNone: () => "Failed to parse key file",
          onSome: (e) => e.message,
        })
        setStep({ step: "error", message: msg })
      }
    }
    input.click()
  }, [setKeypair, setPackedKey, setWasmStatus, setStep])

  const handleExport = useCallback(() => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    const pk = Option.match(packedKey, { onNone: () => null, onSome: (p) => p })
    if (!kp || !pk) return

    const json = exportKeyFile(kp, pk)
    const blob = new Blob([json], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "falcon-keypair.json"
    a.click()
    URL.revokeObjectURL(url)
  }, [keypair, packedKey])

  const hasKeypair = Option.isSome(keypair)
  const hasPacked = Option.isSome(packedKey)

  const keypairHex = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => "0x" + bytesToHex(kp.verifyingKey),
  })

  const nttCoeffs = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => Array.from(kp.publicKeyNtt),
  })

  const packedSlots = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => pk.slots,
  })

  return (
    <div className="space-y-5">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Key Management</h3>

      <div className="flex flex-wrap gap-2">
        <button
          onClick={handleGenerate}
          disabled={isBusy}
          className="rounded-xl bg-gradient-to-b from-falcon-primary to-falcon-primary/80 px-5 py-2.5 text-sm font-semibold text-white shadow-md shadow-falcon-primary/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-primary/20 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
        >
          {isBusy ? "Generating..." : "Generate"}
        </button>
        <button
          onClick={handleImport}
          disabled={isBusy}
          className="rounded-xl px-5 py-2.5 text-sm font-medium text-falcon-text/60 transition-all duration-200 hover:scale-[1.02] hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
          style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
        >
          Import
        </button>
        <button
          onClick={handleExport}
          disabled={!hasKeypair || !hasPacked}
          className="rounded-xl px-5 py-2.5 text-sm font-medium text-falcon-text/60 transition-all duration-200 hover:scale-[1.02] hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
          style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
        >
          Export
        </button>
      </div>

      {keypairHex !== null && (
        <div className="space-y-4">
          <HexDisplay
            label="Verifying Key (896-byte h polynomial)"
            value={keypairHex}
            truncate={{ head: 18, tail: 8 }}
          />

          {nttCoeffs !== null && (
            <div>
              <button
                onClick={() => setShowNtt(!showNtt)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showNtt ? "\u25BC" : "\u25B6"}</span>
                NTT Coefficients ({nttCoeffs.length})
              </button>
              {showNtt && (
                <div className="mt-2 max-h-32 overflow-y-auto rounded-lg px-3 py-2 font-mono text-xs text-falcon-accent/50" style={{ background: "var(--glass-bg)" }}>
                  [{nttCoeffs.slice(0, 20).join(", ")}
                  {nttCoeffs.length > 20 && `, ... ${nttCoeffs.length - 20} more`}]
                </div>
              )}
            </div>
          )}

          {packedSlots !== null && (
            <div>
              <button
                onClick={() => setShowPacked(!showPacked)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showPacked ? "\u25BC" : "\u25B6"}</span>
                Packed Public Key ({packedSlots.length} felt252 slots)
              </button>
              {showPacked && (
                <HexDisplay
                  label=""
                  value={packedSlots}
                  maxRows={29}
                  truncate={{ head: 18, tail: 8 }}
                />
              )}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useCallback } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  messageAtom,
  packedKeyAtom,
  signatureAtom,
  verificationStepAtom,
} from "@/atoms/falcon"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex, getVerificationDisabledState } from "./verification-utils"

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

export function SignVerifyPanel(): React.JSX.Element {
  const message = useAtomValue(messageAtom)
  const keypair = useAtomValue(keypairAtom)
  const step = useAtomValue(verificationStepAtom)
  const signature = useAtomValue(signatureAtom)

  const setMessage = useAtomSet(messageAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setSignature = useAtomSet(signatureAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)

  const { isBusy, canSign } = getVerificationDisabledState({
    keypair,
    message,
    step,
  })

  const handleSignAndVerify = useCallback(async () => {
    const kp = Option.match(keypair, {
      onNone: () => null,
      onSome: (k) => k,
    })
    if (!kp) return

    const startTime = Date.now()
    const messageBytes = new TextEncoder().encode(message)

    setStep({ step: "signing" })
    const signExit = await appRuntime.runPromiseExit(
      FalconService.sign(kp.secretKey, messageBytes),
    )

    if (Exit.isFailure(signExit)) {
      const errOpt = Cause.failureOption(signExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Signing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const sigResult = signExit.value
    setSignature(Option.some(sigResult))

    setStep({ step: "packing" })
    const pkNtt16 = new Uint16Array(kp.publicKeyNtt.length)
    for (let i = 0; i < kp.publicKeyNtt.length; i++) {
      pkNtt16[i] = kp.publicKeyNtt[i]
    }
    const packExit = await appRuntime.runPromiseExit(
      FalconService.packPublicKey(pkNtt16),
    )

    if (Exit.isFailure(packExit)) {
      const errOpt = Cause.failureOption(packExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Packing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    setPackedKey(Option.some(packExit.value))

    setStep({ step: "verifying", substep: "verify" })
    const verifyExit = await appRuntime.runPromiseExit(
      FalconService.verify(kp.verifyingKey, messageBytes, sigResult.signature),
    )

    if (Exit.isFailure(verifyExit)) {
      const errOpt = Cause.failureOption(verifyExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Verification failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const durationMs = Date.now() - startTime
    setStep({ step: "complete", valid: verifyExit.value, durationMs })
  }, [keypair, message, setPackedKey, setSignature, setStep])

  const signatureHex = Option.match(signature, {
    onNone: () => null,
    onSome: (s) => "0x" + bytesToHex(s.signature),
  })

  const saltHex = Option.match(signature, {
    onNone: () => null,
    onSome: (s) => "0x" + bytesToHex(s.salt),
  })

  return (
    <div className="space-y-5">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Sign & Verify</h3>

      <div>
        <label
          htmlFor="message-input"
          className="block text-xs font-medium text-falcon-text/30"
        >
          Message
        </label>
        <input
          id="message-input"
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          disabled={isBusy}
          placeholder="Enter a message to sign..."
          className="mt-2 w-full rounded-xl px-4 py-3 font-mono text-sm text-falcon-text/80 placeholder-falcon-text/20 transition-all duration-200 focus:outline-none focus:ring-1 focus:ring-falcon-primary/30 disabled:cursor-not-allowed disabled:opacity-40"
          style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
        />
      </div>

      <button
        onClick={handleSignAndVerify}
        aria-label="Sign and verify message"
        disabled={!canSign}
        className="rounded-xl bg-gradient-to-b from-falcon-accent to-falcon-accent/80 px-7 py-3 text-sm font-semibold text-white shadow-md shadow-falcon-accent/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-accent/20 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent/40 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
      >
        {step.step === "signing" || step.step === "packing" || step.step === "verifying"
          ? "Running..."
          : "Sign & Verify"}
      </button>

      {signatureHex !== null && step.step === "complete" && (
        <div className="space-y-3">
          <HexDisplay
            label={`Signature (${Option.match(signature, { onNone: () => 0, onSome: (s) => s.signature.length })} bytes)`}
            value={signatureHex}
            truncate={{ head: 18, tail: 8 }}
          />
          {saltHex !== null && (
            <HexDisplay
              label={`Salt (${Option.match(signature, { onNone: () => 0, onSome: (s) => s.salt.length })} bytes)`}
              value={saltHex}
              truncate={{ head: 18, tail: 8 }}
            />
          )}
        </div>
      )}

      {step.step === "complete" && (
        <div
          role="status"
          aria-live="polite"
          className="glass-card-static rounded-2xl p-5"
          style={{
            boxShadow: step.valid ? "var(--glass-shadow-success)" : "var(--glass-shadow-error)",
            borderColor: step.valid ? "rgba(16, 185, 129, 0.15)" : "rgba(239, 68, 68, 0.15)",
          }}
        >
          <div className="flex items-center gap-3">
            <span className={`text-lg font-semibold ${step.valid ? "text-falcon-success" : "text-falcon-error"}`}>
              {step.valid ? "\u2713" : "\u2717"}
            </span>
            <span className="text-sm font-medium text-falcon-text/80">
              {step.valid ? "Signature valid" : "Signature invalid"}
            </span>
            <span className="ml-auto font-mono text-xs text-falcon-text/30">{step.durationMs}ms</span>
          </div>
        </div>
      )}

      {step.step === "error" && (
        <div
          role="alert"
          aria-live="polite"
          className="glass-card-static rounded-2xl p-5"
          style={{
            boxShadow: "var(--glass-shadow-error)",
            borderColor: "rgba(239, 68, 68, 0.15)",
          }}
        >
          <div className="flex items-start gap-3">
            <span className="text-lg font-semibold text-falcon-error">{"\u2717"}</span>
            <div className="flex-1">
              <p className="text-sm font-medium text-falcon-error/80">Error</p>
              <p className="mt-1 break-all text-xs text-falcon-text/30">{step.message}</p>
            </div>
            <button
              onClick={() => setStep({ step: "idle" })}
              className="ml-auto rounded-lg px-3 py-1 text-xs text-falcon-text/40 transition-colors duration-200 hover:text-falcon-text/70"
              style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
            >
              Try Again
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useCallback, useEffect, useRef } from "react"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import {
  pipelineStepsAtom,
  pipelineActiveStepAtom,
  pipelinePlayingAtom,
  INITIAL_PIPELINE_STEPS,
} from "@/atoms/pipeline"
import type { PipelineStep } from "@/services/types"

const TOTAL_STEPS = INITIAL_PIPELINE_STEPS.reduce(
  (sum, s) => sum + s.stepCount,
  0,
)

export function PipelineVisualizer(): React.JSX.Element {
  const steps = useAtomValue(pipelineStepsAtom)
  const activeStep = useAtomValue(pipelineActiveStepAtom)
  const playing = useAtomValue(pipelinePlayingAtom)

  const setSteps = useAtomSet(pipelineStepsAtom)
  const setActiveStep = useAtomSet(pipelineActiveStepAtom)
  const setPlaying = useAtomSet(pipelinePlayingAtom)

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null)

  useEffect(() => {
    if (!playing) {
      if (intervalRef.current) clearInterval(intervalRef.current)
      return
    }

    intervalRef.current = setInterval(() => {
      setActiveStep((prev) => {
        const next = prev + 1
        if (next >= steps.length) {
          setPlaying(false)
          setSteps((s) =>
            s.map((step, i) =>
              i === prev ? { ...step, status: "complete" as const } : step,
            ),
          )
          return prev
        }
        setSteps((s) =>
          s.map((step, i) => {
            if (i === prev) return { ...step, status: "complete" as const }
            if (i === next) return { ...step, status: "active" as const }
            return step
          }),
        )
        return next
      })
    }, 2000)

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current)
    }
  }, [playing, steps.length, setActiveStep, setSteps, setPlaying])

  const handlePlay = useCallback(() => {
    if (activeStep === -1) {
      setSteps((s) =>
        s.map((step, i) =>
          i === 0
            ? { ...step, status: "active" as const }
            : { ...step, status: "pending" as const },
        ),
      )
      setActiveStep(0)
    }
    setPlaying(true)
  }, [activeStep, setSteps, setActiveStep, setPlaying])

  const handlePause = useCallback(() => {
    setPlaying(false)
  }, [setPlaying])

  const handleStep = useCallback(() => {
    setPlaying(false)
    setActiveStep((prev) => {
      const next = prev + 1
      if (next >= steps.length) {
        setSteps((s) =>
          s.map((step, i) =>
            i === prev ? { ...step, status: "complete" as const } : step,
          ),
        )
        return prev
      }
      if (prev === -1) {
        setSteps((s) =>
          s.map((step, i) =>
            i === 0
              ? { ...step, status: "active" as const }
              : { ...step, status: "pending" as const },
          ),
        )
        return 0
      }
      setSteps((s) =>
        s.map((step, i) => {
          if (i === prev) return { ...step, status: "complete" as const }
          if (i === next) return { ...step, status: "active" as const }
          return step
        }),
      )
      return next
    })
  }, [steps.length, setActiveStep, setSteps, setPlaying])

  const handleReset = useCallback(() => {
    setPlaying(false)
    setActiveStep(-1)
    setSteps(INITIAL_PIPELINE_STEPS)
  }, [setPlaying, setActiveStep, setSteps])

  const allComplete = steps.every((s) => s.status === "complete")

  return (
    <section id="pipeline" className="px-8 py-32 lg:px-8">
      <div className="mx-auto max-w-6xl">
        <div className="flex flex-wrap items-baseline justify-between gap-4">
          <div>
            <h2 className="text-4xl font-semibold tracking-[-0.02em] text-falcon-text">
              Verification Pipeline
            </h2>
            <p className="mt-3 text-sm text-falcon-text/40">
              Step through the 6-stage Falcon-512 on-chain verification
            </p>
          </div>
          <span className="font-mono text-xs text-falcon-accent/50">
            ~{TOTAL_STEPS.toLocaleString()} total steps
          </span>
        </div>

        {/* Glass toolbar */}
        <div
          className="mt-8 inline-flex items-center gap-1 rounded-full p-1"
          style={{ background: "var(--glass-bg)", border: "1px solid var(--glass-border)" }}
        >
          {!playing ? (
            <button
              onClick={handlePlay}
              disabled={allComplete}
              aria-label="Play pipeline animation"
              className="rounded-full bg-gradient-to-b from-falcon-primary to-falcon-primary/80 px-5 py-2 text-xs font-semibold text-white shadow-sm transition-all duration-200 hover:scale-[1.02] disabled:cursor-not-allowed disabled:opacity-40"
            >
              Play
            </button>
          ) : (
            <button
              onClick={handlePause}
              aria-label="Pause pipeline animation"
              className="rounded-full bg-gradient-to-b from-falcon-primary to-falcon-primary/80 px-5 py-2 text-xs font-semibold text-white shadow-sm transition-all duration-200 hover:scale-[1.02]"
            >
              Pause
            </button>
          )}
          <button
            onClick={handleStep}
            disabled={playing || allComplete}
            aria-label="Advance one pipeline step"
            className="rounded-full px-4 py-2 text-xs font-medium text-falcon-text/50 transition-all duration-200 hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
          >
            Step
          </button>
          <button
            onClick={handleReset}
            aria-label="Reset pipeline to beginning"
            className="rounded-full px-4 py-2 text-xs font-medium text-falcon-text/50 transition-all duration-200 hover:text-falcon-text/80"
          >
            Reset
          </button>
        </div>

        {/* Pipeline step cards */}
        <div className="mt-8 grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
          {steps.map((step) => (
            <PipelineStepCard key={step.id} step={step} />
          ))}
        </div>
      </div>
    </section>
  )
}

function PipelineStepCard({ step }: { step: PipelineStep }): React.JSX.Element {
  const isActive = step.status === "active"
  const isComplete = step.status === "complete"

  return (
    <div
      className="glass-card-static rounded-3xl p-6 transition-all duration-300"
      style={{
        boxShadow: isActive
          ? "var(--glass-shadow), var(--glass-shadow-glow)"
          : isComplete
            ? "var(--glass-shadow), var(--glass-shadow-success)"
            : "var(--glass-shadow)",
        borderColor: isActive
          ? "rgba(99, 102, 241, 0.2)"
          : isComplete
            ? "rgba(16, 185, 129, 0.12)"
            : undefined,
        background: isComplete
          ? "rgba(16, 185, 129, 0.03)"
          : undefined,
      }}
    >
      <div className="flex items-center gap-3">
        <span>
          {isComplete ? (
            <span className="text-sm text-falcon-success">&#10003;</span>
          ) : isActive ? (
            <span className="inline-block h-2.5 w-2.5 animate-pulse rounded-full bg-falcon-primary shadow-[0_0_8px_rgba(99,102,241,0.4)]" />
          ) : (
            <span className="inline-block h-2.5 w-2.5 rounded-full bg-falcon-text/10" />
          )}
        </span>
        <h3 className="font-mono text-xs font-semibold text-falcon-text/80">
          {step.name}
        </h3>
        <span className="ml-auto font-mono text-[10px] text-falcon-text/25">
          ~{step.stepCount.toLocaleString()}
        </span>
      </div>

      <p className="mt-3 text-xs leading-relaxed text-falcon-text/30">{step.description}</p>

      {isActive && (
        <div className="mt-4 space-y-1.5 pt-4" style={{ borderTop: "1px solid var(--glass-border)" }}>
          <div className="text-xs">
            <span className="text-falcon-text/25">In: </span>
            <span className="font-mono text-falcon-text/50">{step.input}</span>
          </div>
          <div className="text-xs">
            <span className="text-falcon-text/25">Out: </span>
            <span className="font-mono text-falcon-text/50">{step.output}</span>
          </div>
        </div>
      )}
    </div>
  )
}

