        <input
          id="message-input"
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          disabled={isBusy}
          placeholder="Enter a message to sign..."
          className="glass-input mt-2 w-full px-4 py-3 font-mono text-sm text-falcon-text/80 placeholder-falcon-text/20"
