          <div
            className="glass-card-static mt-6 rounded-2xl p-5"
            style={{ borderColor: "rgba(234, 179, 8, 0.15)", boxShadow: "0 0 30px -5px rgba(234, 179, 8, 0.1)" }}
          >
            <p className="text-sm text-yellow-400/80">
              FalconAccount not declared on {networkConfig.name}.
              Run: <code className="rounded-md px-1.5 py-0.5 font-mono text-xs" style={{ background: "var(--glass-bg)" }}>./bin/declare.sh {networkConfig.id}</code>
            </p>
          </div>
        )}
        <p className="sr-only" aria-live="polite">
          {liveStatus}
